from lxml import etree

def process_soap_request(xml_request):
    # Prevent XML External Entity (XXE) attacks
    parser = etree.XMLParser(resolve_entities=False)
    
    # Parse the XML request
    try:
        root = etree.fromstring(xml_request.encode('utf-8'), parser)
    except etree.XMLSyntaxError as e:
        return f"XML Syntax Error: {str(e)}"

    # Validate against DTD if needed (assuming DTD is defined in the XML)
    dtd = etree.DTD(etree.XML('''<!DOCTYPE envelope [
        <!ELEMENT envelope (header, body)>
        <!ELEMENT header (#PCDATA)>
        <!ELEMENT body (#PCDATA)>
    ]'''))
    
    if not dtd.validate(root):
        return "DTD Validation Error"

    # Extract the SOAP body
    body = root.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
    if body is not None:
        return etree.tostring(body, pretty_print=True).decode('utf-8')
    else:
        return "No SOAP Body Found"